import React, { useState, useEffect, useMemo } from "react";
import { Link, useParams, useLocation, useNavigate } from "react-router-dom";
import Footer from "./Footer";
import { createSelector } from "reselect";
import { useDispatch, useSelector } from "react-redux";
import { getAllProducts } from "../features/products/productSlice";
import HomeAds from "./HomeAds";
import ProductCard from "./ProductCard";

const selectWishlist = createSelector(
  (state) => state?.auth?.wishlist?.wishlist,
  (wishlist) => wishlist || [],
);

function OTC() {
  const navigate = useNavigate();
  const getTokenFromLocalStorage = useMemo(() => {
    return localStorage.getItem("customer")
      ? JSON.parse(localStorage.getItem("customer"))
      : null;
  }, []);

  const { id } = useParams();
  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(0);
  const [query, setQuery] = useState("");
  const [filteredData, setFilteredData] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const productsPerPage = 12;
  const location = useLocation();
  const dispatch = useDispatch();
  const [sortOrder, setSortOrder] = useState("latest");
  const [viewMode, setViewMode] = useState("grid");

  const {
    product,
    isError: productError,
    message: productMessage,
  } = useSelector((state) => state.product);
  
  const addedToWish = useSelector(selectWishlist);

  useEffect(() => {
    dispatch(getAllProducts());
  }, [dispatch, id]);

  const filterData = () => {
    const lowerCaseQuery = (query || "").toLowerCase();

    let filtered = product.filter((p) => {
      // In OTC.js, it filters by "Personal Care"
      if (p.category !== "Personal Care") return false;
      
      const price = parseInt(p.price);
      const isPriceInRange =
        (minPrice === 0 || price >= minPrice) &&
        (maxPrice === 0 || price <= maxPrice);

      const matchesQuery =
        (p.title || "").toLowerCase().includes(lowerCaseQuery) ||
        (p.subcategory || "").toLowerCase().includes(lowerCaseQuery);

      return isPriceInRange && matchesQuery;
    });

    if (sortOrder === "latest") {
      filtered.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
    } else if (sortOrder === "oldest") {
      filtered.sort((a, b) => new Date(a.updatedAt) - new Date(b.updatedAt));
    } else if (sortOrder === "priceLow") {
      filtered.sort((a, b) => a.price - b.price);
    } else if (sortOrder === "priceHigh") {
      filtered.sort((a, b) => b.price - a.price);
    }

    setFilteredData(filtered);
  };

  useEffect(() => {
    if (product && product.length > 0) {
      filterData();
    }
  }, [product, query, minPrice, maxPrice, sortOrder]);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const queryParam = params.get("query") || "";
    setQuery(queryParam);
  }, [location.search]);

  const handlePageChange = (pageNumber) => {
    setCurrentPage(pageNumber);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const indexOfLastProduct = currentPage * productsPerPage;
  const indexOfFirstProduct = indexOfLastProduct - productsPerPage;
  const currentProducts = filteredData.slice(indexOfFirstProduct, indexOfLastProduct);
  const pageNumbers = Array.from({ length: Math.ceil(filteredData.length / productsPerPage) }, (_, i) => i + 1);

  if (!navigator.onLine) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="text-center p-10 bg-white rounded-[40px] shadow-sm border border-slate-100">
          <h2 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tight">Offline</h2>
          <p className="text-slate-400 font-medium">Please check your internet connection.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-[#f8fafc] min-h-screen pb-20">
      <main className="max-w-[1440px] mx-auto pt-16 md:pt-24 lg:pt-32">
        <HomeAds category="Personal Care" />

        <section className="px-4 lg:px-10 py-10 md:py-16">
          {/* Header Area */}
          <div className="bg-white rounded-[40px] p-6 md:p-10 shadow-sm border border-slate-100 mb-12">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
              <div className="space-y-2">
                <div className="flex items-center gap-3 text-[11px] text-teal-600 font-black uppercase tracking-widest bg-teal-50 w-fit px-3 py-1 rounded-full">
                  <span className="w-1.5 h-1.5 bg-teal-500 rounded-full animate-pulse"></span>
                  Personal wellness
                </div>
                <h1 className="text-3xl md:text-5xl font-black text-slate-900 tracking-tighter uppercase italic">
                   Personal <span className="text-teal-600">Care</span>
                </h1>
                <p className="text-slate-400 font-medium text-sm md:text-base max-w-xl">
                  Daily essentials and wellness products. Premium self-care items curated for your health and comfort.
                </p>
              </div>

              <div className="flex flex-wrap items-center gap-4">
                 <div className="relative group min-w-[200px]">
                   <select
                    className="appearance-none bg-slate-50 border border-slate-100 text-slate-900 text-xs font-black rounded-2xl focus:ring-4 focus:ring-teal-500/10 focus:border-teal-500 block w-full pl-5 pr-10 py-4 cursor-pointer transition-all hover:bg-white hover:border-slate-200 uppercase tracking-widest"
                    value={sortOrder}
                    onChange={(e) => setSortOrder(e.target.value)}
                  >
                    <option value="latest">Latest Arrivals</option>
                    <option value="priceLow">Price: Lowest first</option>
                    <option value="priceHigh">Price: Highest first</option>
                    <option value="oldest">Legacy Stock</option>
                  </select>
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
                  </span>
                </div>

                <div className="flex items-center gap-3 bg-slate-50 p-1.5 rounded-2xl border border-slate-100">
                   <button
                    onClick={() => setViewMode("grid")}
                    className={`w-11 h-11 flex items-center justify-center rounded-xl transition-all duration-300 ${viewMode === "grid" ? "bg-white text-teal-600 shadow-md ring-1 ring-slate-200/50" : "text-slate-400 hover:text-slate-600"}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><rect width="7" height="7" x="3" y="3" rx="1"/><rect width="7" height="7" x="14" y="3" rx="1"/><rect width="7" height="7" x="14" y="14" rx="1"/><rect width="7" height="7" x="3" y="14" rx="1"/></svg>
                  </button>
                  <button
                    onClick={() => setViewMode("list")}
                    className={`w-11 h-11 flex items-center justify-center rounded-xl transition-all duration-300 ${viewMode === "list" ? "bg-white text-teal-600 shadow-md ring-1 ring-slate-200/50" : "text-slate-400 hover:text-slate-600"}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>
                  </button>
                </div>
              </div>
            </div>
            
            <div className="mt-10 pt-8 border-t border-slate-50">
              <div className="flex-1 relative">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                </span>
                <input 
                  type="text"
                  placeholder="Filter products by name or subcategory..."
                  className="w-full bg-slate-50 border-none rounded-2xl pl-12 pr-6 py-4 text-sm font-bold text-slate-900 placeholder:text-slate-300 focus:ring-4 focus:ring-teal-500/10 transition-all shadow-inner"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                />
              </div>
            </div>
          </div>

          {filteredData.length === 0 ? (
            <div className="bg-white rounded-[40px] py-40 px-10 text-center border border-slate-100 shadow-sm">
                <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-100 scale-150">
                   <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                </div>
                <h3 className="text-3xl font-black text-slate-900 tracking-tight uppercase mb-2">No matching products</h3>
                <p className="text-slate-400 font-medium max-w-sm mx-auto mb-10">We couldn't find matches for <span className="text-teal-600 font-bold">"{query}"</span> in our Personal Care range.</p>
                <button onClick={() => {setQuery(""); setMinPrice(0); setMaxPrice(0);}} className="px-8 py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-teal-600 transition-all uppercase tracking-widest text-[10px]">Reset Catalog View</button>
            </div>
          ) : (
            <div className={viewMode === "grid" ? "grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 md:gap-10" : "flex flex-col gap-8"}>
              {currentProducts.map((p) => (
                <ProductCard key={p._id} product={p} viewMode={viewMode} />
              ))}
            </div>
          )}

          {pageNumbers.length > 1 && (
             <div className="mt-24 flex justify-center items-center gap-4">
               {pageNumbers.map((num) => (
                 <button
                    key={num}
                    onClick={() => handlePageChange(num)}
                    className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black transition-all duration-300 ${currentPage === num ? "bg-teal-600 text-white shadow-2xl shadow-teal-600/40 scale-110" : "bg-white text-slate-400 hover:bg-slate-50 border border-slate-100 shadow-sm active:scale-95"}`}
                 >
                   {num}
                 </button>
               ))}
             </div>
          )}
        </section>
      </main>
      <Footer />
    </div>
  );
}

export default OTC;
