import React from "react";
import { Link } from "react-router-dom";
import { AiFillHeart, AiOutlineHeart } from "react-icons/ai";
import { useDispatch, useSelector } from "react-redux";
import { addToWishlist } from "../redux/actions/wishListActon";
import { useNavigate } from "react-router-dom";

const ProductCard = ({ product, viewMode = "grid" }) => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const addedToWish = useSelector((state) => state?.auth?.wishlist?.wishlist || []);

  const getProductImage = (p, index = 0) => {
    try {
      if (p.images && Array.isArray(p.images) && p.images[index] && p.images[index].secure_url) {
        return p.images[index].secure_url;
      }
      if (p.colors && Array.isArray(p.colors) && p.colors[0] && p.colors[0].images && Array.isArray(p.colors[0].images) && p.colors[0].images[index] && p.colors[0].images[index].secure_url) {
        return p.colors[0].images[index].secure_url;
      }
      if (index > 0) return getProductImage(p, 0);
    } catch (e) {
      console.error("Image access error", e);
    }
    return "https://res.cloudinary.com/dpkv77m87/image/upload/v1711200000/fallback_product_image.png";
  };

  const handleWishlist = (e) => {
    e.preventDefault();
    e.stopPropagation();
    dispatch(addToWishlist(product._id, navigate, 1));
  };

  const isLiked = addedToWish.some((w) => w._id === product._id);

  if (viewMode === "list") {
    return (
      <div className="group flex flex-col md:flex-row bg-white rounded-[32px] border border-slate-100 p-4 gap-6 transition-all duration-500 hover:shadow-2xl hover:shadow-slate-200/50 hover:border-teal-100 mb-6">
        <div className="relative w-full md:w-56 aspect-square rounded-2xl overflow-hidden bg-slate-50 flex-shrink-0">
          <Link to={`/productdetails/${product._id}`} className="block w-full h-full">
            <img
              className="w-full h-full object-contain transition-transform duration-700 group-hover:scale-110"
              src={getProductImage(product, 0)}
              alt={product.title}
            />
          </Link>
          <button
            onClick={handleWishlist}
            className="absolute top-3 right-3 w-10 h-10 bg-white/80 backdrop-blur-md shadow-lg rounded-full flex items-center justify-center text-slate-400 hover:text-red-500 transition-all active:scale-75 z-10"
          >
            {isLiked ? <AiFillHeart color="#ef4444" size={22} /> : <AiOutlineHeart size={22} />}
          </button>
        </div>

        <div className="flex-1 flex flex-col justify-between py-2">
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <span className="px-2 py-0.5 bg-teal-50 text-teal-600 text-[10px] font-black uppercase tracking-widest rounded-md">
                {product.category}
              </span>
              {product.quantity > 0 ? (
                <span className="text-[10px] font-bold text-emerald-500 bg-emerald-50 px-2 py-0.5 rounded-md uppercase tracking-wider">In Stock</span>
              ) : (
                <span className="text-[10px] font-bold text-rose-500 bg-rose-50 px-2 py-0.5 rounded-md uppercase tracking-wider">Out of Stock</span>
              )}
            </div>
            
            <Link to={`/productdetails/${product._id}`} className="block">
              <h3 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight transition-colors group-hover:text-teal-600 line-clamp-2">
                {product.title}
              </h3>
            </Link>
            
            <p className="text-slate-500 text-sm font-medium line-clamp-3 leading-relaxed max-w-2xl" dangerouslySetInnerHTML={{ __html: product.description }}></p>
          </div>

          <div className="mt-6 flex flex-wrap items-center justify-between gap-4">
            <div className="flex flex-col">
              <span className="text-slate-400 text-xs font-black uppercase tracking-widest opacity-60">Premium Value</span>
              <span className="text-2xl font-black text-slate-900 tracking-tighter flex items-baseline gap-1">
                {product.price} <span className="text-sm font-black text-teal-600 uppercase">ETB</span>
              </span>
            </div>
            
            <Link 
              to={`/productdetails/${product._id}`}
              className="px-8 py-4 bg-slate-950 text-white font-black rounded-2xl hover:bg-teal-600 transition-all shadow-xl shadow-slate-900/10 active:scale-95 uppercase tracking-widest text-[10px] flex items-center gap-2"
            >
              Clinical Details
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="group relative bg-white rounded-[32px] border border-slate-100 p-3 pb-6 transition-all duration-500 hover:shadow-2xl hover:shadow-slate-200/50 hover:border-teal-100 ring-0 hover:ring-1 hover:ring-teal-100/50 h-full flex flex-col">
      <div className="relative aspect-square rounded-2xl overflow-hidden bg-slate-50 mb-5">
        <Link to={`/productdetails/${product._id}`} className="block w-full h-full">
          <img
            className="w-full h-full object-contain transition-all duration-700 group-hover:scale-110"
            src={getProductImage(product, 0)}
            alt={product.title}
          />
        </Link>
        <button
          onClick={handleWishlist}
          className="absolute top-3 right-3 w-10 h-10 bg-white/80 backdrop-blur-md shadow-lg rounded-full flex items-center justify-center text-slate-400 hover:text-red-500 transition-all active:scale-75 z-10"
        >
          {isLiked ? <AiFillHeart color="#ef4444" size={22} /> : <AiOutlineHeart size={22} />}
        </button>
        <span className={`absolute bottom-3 left-3 px-3 py-1 text-[10px] font-black uppercase tracking-widest rounded-lg shadow-sm ${product.quantity > 0 ? "bg-teal-500 text-white" : "bg-red-500 text-white"}`}>
          {product.quantity > 0 ? "In Stock" : "Out of Stock"}
        </span>
      </div>

      <div className="px-2 space-y-3 flex-1 flex flex-col">
        <span className="text-[10px] font-black text-teal-600 uppercase tracking-widest block opacity-70">
          {product.category}
        </span>
        <Link to={`/productdetails/${product._id}`} className="block flex-1">
          <h3 className="text-base font-black text-slate-900 tracking-tight leading-snug transition-colors group-hover:text-teal-600 line-clamp-2">
            {product.title}
          </h3>
        </Link>
        <div className="pt-2 flex items-center justify-between">
          <span className="text-xl font-black text-slate-900 tracking-tighter flex items-baseline gap-1">
            {product.price} <span className="text-[10px] font-black text-teal-600 uppercase">ETB</span>
          </span>
          <Link
            to={`/productdetails/${product._id}`}
            className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-900 hover:bg-teal-600 hover:text-white transition-all transform group-hover:scale-110 active:scale-95 shadow-sm"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;
